fd_hdi_low = fd_effect["hdi_3%"]
fd_hdi_high = fd_effect["hdi_97%"]

ax.errorbar(
    naive_val,
    1,
    xerr=[[naive_val - naive_hdi[0]], [naive_hdi[1] - naive_val]],
